#include <iostream>
#include <string>
#include <sstream>
#include <vector>

// Function to run the user's code with a given input
std::string run_user_code(const std::string& input) {
    std::stringstream ss_input(input);
    std::stringstream ss_output;

    // Redirect cin and cout
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    extern void solve(); // Declare the user's solve function
    solve();

    // Restore cin and cout
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    return ss_output.str();
}

// Helper to format expected output
std::string format_output(int h, int m, int s) {
    std::ostringstream oss;
    oss << "Hours: " << h << "\n"
        << "Minutes: " << m << "\n"
        << "Seconds: " << s << "\n";
    return oss.str();
}

int main() {
    std::vector<std::string> inputs = {
        "3665",
        "7200",
        "59"
    };

    std::vector<std::string> expected_outputs = {
        format_output(1, 1, 5),
        format_output(2, 0, 0),
        format_output(0, 0, 59)
    };

    for (size_t i = 0; i < inputs.size(); ++i) {
        std::string actual_output = run_user_code(inputs[i]);
